import pandas as pd
from collections import defaultdict

# Get books data
books_data = locals()['var_functions.query_db:12']
reviews_data = locals()['var_functions.query_db:18']

# Load files if needed
if isinstance(books_data, str) and books_data.endswith('.json'):
    with open(books_data, 'r') as f:
        books_data = json.load(f)
if isinstance(reviews_data, str) and reviews_data.endswith('.json'):
    with open(reviews_data, 'r') as f:
        reviews_data = json.load(f)

# Create mapping from numeric ID
book_numeric_to_id = {}
for book in books_data:
    numeric_id = int(book['book_id'].split('_')[1])
    book_numeric_to_id[numeric_id] = book['book_id']

# Calculate average rating per book
book_ratings = defaultdict(list)
for review in reviews_data:
    purchase_numeric = int(review['purchase_id'].split('_')[1])
    if purchase_numeric in book_numeric_to_id:
        book_id = book_numeric_to_id[purchase_numeric]
        book_ratings[book_id].append(float(review['rating']))

# Calculate averages
book_avg_ratings = {}
for book_id, ratings in book_ratings.items():
    if ratings:
        avg_rating = sum(ratings) / len(ratings)
        book_avg_ratings[book_id] = avg_rating

# Find books with perfect 5.0 average
perfect_books = []
for book in books_data:
    book_id = book['book_id']
    if book_id in book_avg_ratings and book_avg_ratings[book_id] == 5.0:
        perfect_books.append({
            'title': book['title'],
            'book_id': book_id,
            'avg_rating': book_avg_ratings[book_id],
            'review_count': len(book_ratings[book_id])
        })

result = json.dumps(perfect_books, indent=2)
print('__RESULT__:')
